type tagsQuickRange struct {
	Label string
	URL   string
}

func tagsQuickRanges() []tagsQuickRange {
	now := time.Now().UTC()
	y := now.Year()
	m := now.Month()
	today := now.Format("2006-01-02")

	thisMonthStart := fmt.Sprintf("%d-%02d-01", y, m)

	lastMonthEnd := time.Date(y, m, 1, 0, 0, 0, 0, time.UTC).AddDate(0, 0, -1)
	lastMonthStart := fmt.Sprintf("%d-%02d-01", lastMonthEnd.Year(), lastMonthEnd.Month())

	threeMonthsAgo := now.AddDate(0, -3, 0).Format("2006-01-02")
	sixMonthsAgo := now.AddDate(0, -6, 0).Format("2006-01-02")

	return []tagsQuickRange{
		{"This Month", fmt.Sprintf("/tags?date_from=%s&date_to=%s", thisMonthStart, today)},
		{"Last Month", fmt.Sprintf("/tags?date_from=%s&date_to=%s", lastMonthStart, lastMonthEnd.Format("2006-01-02"))},
		{"Last 3M", fmt.Sprintf("/tags?date_from=%s&date_to=%s", threeMonthsAgo, today)},
		{"Last 6M", fmt.Sprintf("/tags?date_from=%s&date_to=%s", sixMonthsAgo, today)},
	}
}

func tagsFilterURL(tagID, dateFrom, dateTo string) string {
	url := "/transactions?tag_id=" + tagID
	if dateFrom != "" {
		url += "&date_from=" + dateFrom
	}
	if dateTo != "" {
		url += "&date_to=" + dateTo
	}
	return url
}

func tagsSpendTotal(rows []db.GetSpendByTagRow) float64 {
	var t float64
	for _, r := range rows {
		t += r.Total
	}
	return t
}

